INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bd4c58dd-3d04-4809-a13b-151deb5651bf',
  '00000000-0000-0000-0000-000000000001',
  $escape$OWASP - Dynamic Application Security Testing with Burp Suite and ZAP$escape$,
  $escape$OWASP's ZAP (Zed Attack Proxy) and Burp Suite are popular tools for DAST (Dynamic Application Security Testing). ZAP is a free, open-source tool that can be integrated with various testing frameworks, including OWASP's ESAPI (Enterprise Security API). Burp Suite, on the other hand, offers advanced features like dynamic analysis and manual testing. To start testing with ZAP, import your application's URL and configure the proxy settings. Use the 'Spider' feature to map the application's structure and identify potential vulnerabilities. In Burp Suite, use the 'Target' feature to set your application's URL and configure the proxy settings. Run a 'Basic Scan' to identify common vulnerabilities like SQL injection and cross-site scripting (XSS).$escape$,
  NULL,
  NULL,
