INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9a3ef6c8-2e50-4fb8-8494-be3300cd1f64',
  '00000000-0000-0000-0000-000000000001',
  $escape$OWASP: Taming SonarQube's Hotspots and Issues$escape$,
  $escape$When using OWASP's ZAP with SonarQube, it's essential to understand the difference between hotspots and issues. Hotspots represent the most critical vulnerabilities, while issues are lower-priority findings. To configure SonarQube quality gates, create a new project and navigate to 'Configuration > Quality Profiles > New Profile'. In the profile settings, select 'OWASP Top Ten' and set the 'Hotspot Severity' to 'BLOCKER'. This ensures that only critical vulnerabilities block the build. To identify hotspots, use the following SQL query in SonarQube's database: `SELECT id, component, message FROM issues WHERE severity = 'BLOCKER';`$escape$,
  NULL,
  NULL,
