INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '87c428c7-3acd-4ad9-8e84-f30452e713e3',
  '00000000-0000-0000-0000-000000000001',
  $escape$owasp: Securing Your App with Security Headers$escape$,
  $escape$When configuring security headers in OWASP, it's essential to understand the interplay between CSP, HSTS, X-Frame-Options, and Referrer-Policy. CSP (Content Security Policy) defines allowed sources for scripts, styles, and images. HSTS (HTTP Strict Transport Security) enforces HTTPS. X-Frame-Options prevents clickjacking, while Referrer-Policy controls referrer information sharing. For example, using OWASP's ZAP and ModSecurity, you can configure these headers with the following ZAP API calls: `zap.httpssettings.setHsts(includeSubdomains=True, preload=True)` and `zap.httpssettings.setCsp('script-src https://example.com; object-src https://example.com')`. This helps protect your application from common web attacks.$escape$,
  NULL,
  NULL,
